:root {
  --color-primary-100: #00A7E5;
  --color-primary-200: #0084FF;
  --color-primary-300: #005BAA;
  --color-secondary-green: #26A65B;
  --color-secondary-orange: #F15A29;
  --color-accent-blue: #0084FF;
  --color-neutral-000: #FFFFFF;
  --color-neutral-050: #F5F7FA;
  --color-neutral-100: #E5E9F0;
  --color-neutral-900: #333333;
  --color-border-subtle: #E1E4EA;
  --color-shadow-soft: rgba(0, 0, 0, 0.08);

  --color-success: #28A745;
  --color-error: #E53935;
  --color-warning: #FFC107;
  --color-info: #17A2B8;

  --font-heading: "DM Sans", "Helvetica Neue", Helvetica, Arial, sans-serif;
  --font-body: "Source Sans 3", Helvetica, Arial, sans-serif;
  --font-code: "Source Code Pro", Menlo, Monaco, Consolas, "Courier New", monospace;

  --font-size-h1: 32px;
  --font-size-h2: 24px;
  --font-size-h3: 20px;
  --font-size-body: 16px;
  --font-size-small: 13px;

  --font-weight-light: 300;
  --font-weight-regular: 400;
  --font-weight-medium: 500;
  --font-weight-semibold: 600;
  --font-weight-bold: 700;

  --line-height-tight: 1.2;
  --line-height-normal: 1.5;
  --line-height-relaxed: 1.7;

  --space-0-5: 4px;
  --space-1: 8px;
  --space-2: 16px;
  --space-3: 24px;
  --space-4: 32px;
  --space-5: 48px;
  --space-6: 64px;

  --header-height-topbar: 32px;
  --header-height-main: 88px;
  --max-width-container: 1200px;
}

*,
*::before,
*::after {
  box-sizing: border-box;
}

html {
  font-size: 100%;
}

body {
  margin: 0;
  font-family: var(--font-body);
  font-size: var(--font-size-body);
  line-height: var(--line-height-normal);
  color: var(--color-neutral-900);
  background-color: var(--color-neutral-000);
}

img {
  max-width: 100%;
  height: auto;
  display: block;
}

a {
  color: inherit;
  text-decoration: none;
}

a:hover {
  text-decoration: none;
}

.site-wrapper {
  min-height: 100vh;
  display: flex;
  flex-direction: column;
}

.site-content {
  flex: 1 0 auto;
  background-color: var(--color-neutral-000);
}

.container {
  max-width: var(--max-width-container);
  margin-left: auto;
  margin-right: auto;
  padding-left: var(--space-3);
  padding-right: var(--space-3);
}

/* Typography scale */

h1,
h2,
h3,
h4 {
  margin-top: 0;
  font-family: var(--font-heading);
  color: var(--color-neutral-900);
}

h1 {
  font-size: var(--font-size-h1);
  line-height: var(--line-height-tight);
}

h2 {
  font-size: var(--font-size-h2);
  line-height: var(--line-height-tight);
}

h3 {
  font-size: var(--font-size-h3);
  line-height: var(--line-height-tight);
}

p {
  margin-top: 0;
  margin-bottom: var(--space-2);
}

.small-text {
  font-size: var(--font-size-small);
}

/* Top utility bar */

.top-bar {
  background-color: var(--color-accent-blue);
  color: var(--color-neutral-000);
  font-size: var(--font-size-small);
}

.top-bar-inner {
  display: flex;
  align-items: center;
  justify-content: space-between;
  height: var(--header-height-topbar);
}

.top-bar-left,
.top-bar-right {
  display: flex;
  align-items: center;
  gap: var(--space-1);
}

.top-bar-icon {
  font-size: 14px;
}

.top-bar-label {
  font-weight: var(--font-weight-semibold);
}

/* Main header */

.site-header {
  box-shadow: 0 1px 0 var(--color-border-subtle);
}

.main-header {
  background-color: var(--color-neutral-000);
}

.main-header-inner {
  display: flex;
  align-items: flex-end;
  justify-content: space-between;
  gap: var(--space-4);
  height: var(--header-height-main);
}

.logo {
  display: flex;
  flex-direction: column;
  justify-content: center;
  gap: var(--space-0-5);
  text-decoration: none;
}

.logo-text-primary {
  font-family: var(--font-heading);
  font-size: 28px;
  line-height: var(--line-height-tight);
  font-weight: var(--font-weight-bold);
  color: var(--color-primary-300);
}

.logo-text-secondary {
  font-size: 12px;
  text-transform: uppercase;
  letter-spacing: 0.12em;
  font-weight: var(--font-weight-medium);
  color: var(--color-secondary-green);
}

/* Primary navigation */

.main-nav {
  flex: 1 1 auto;
}

.main-nav-list {
  list-style: none;
  margin: 0;
  padding: 0;
  display: flex;
  align-items: flex-end;
  justify-content: flex-end;
  flex-wrap: wrap;
  row-gap: var(--space-1);
}

.main-nav-item {
  margin-left: var(--space-3);
}

.main-nav-link {
  display: inline-block;
  padding-bottom: 10px;
  text-transform: uppercase;
  font-family: var(--font-heading);
  font-size: 14px;
  letter-spacing: 0.08em;
  font-weight: var(--font-weight-medium);
  color: var(--color-neutral-900);
  border-bottom: 3px solid transparent;
  transition: color 0.15s ease-out, border-color 0.15s ease-out;
}

.main-nav-link:hover,
.main-nav-link:focus-visible {
  color: var(--color-primary-100);
  border-bottom-color: var(--color-primary-100);
}

.main-nav-link.is-active {
  color: var(--color-primary-100);
  border-bottom-color: var(--color-primary-100);
}

.main-nav-link:focus-visible {
  outline: 2px solid var(--color-primary-100);
  outline-offset: 2px;
}

/* Footer */

.site-footer {
  margin-top: var(--space-5);
  background-color: var(--color-neutral-050);
  border-top: 4px solid var(--color-primary-100);
}

.footer-main {
  padding-top: var(--space-4);
  padding-bottom: var(--space-4);
}

.footer-inner {
  display: flex;
  flex-wrap: wrap;
  justify-content: space-between;
  gap: var(--space-4);
}

.footer-brand {
  max-width: 340px;
}

.footer-logo-text {
  font-family: var(--font-heading);
  font-size: 22px;
  font-weight: var(--font-weight-bold);
  color: var(--color-primary-300);
  margin-bottom: var(--space-1);
}

.footer-description {
  margin: 0;
  font-size: 14px;
  line-height: var(--line-height-relaxed);
}

.footer-nav {
  flex: 1 1 260px;
}

.footer-nav-list {
  list-style: none;
  margin: 0;
  padding: 0;
  display: flex;
  flex-wrap: wrap;
  gap: var(--space-1) var(--space-3);
}

.footer-nav-item {
  flex: 0 1 auto;
}

.footer-nav-link {
  font-size: 14px;
  font-weight: var(--font-weight-medium);
  color: var(--color-neutral-900);
}

.footer-nav-link:hover,
.footer-nav-link:focus-visible {
  color: var(--color-primary-100);
  text-decoration: underline;
}

.footer-bottom {
  border-top: 1px solid var(--color-border-subtle);
  background-color: var(--color-neutral-000);
}

.footer-bottom-inner {
  display: flex;
  align-items: center;
  justify-content: center;
  padding-top: var(--space-2);
  padding-bottom: var(--space-2);
}

.footer-copy {
  margin: 0;
  font-size: 13px;
  color: #6B7280;
}

/* Responsive adjustments */

@media (max-width: 960px) {
  .main-header-inner {
    flex-direction: column;
    align-items: flex-start;
    height: auto;
    padding-top: var(--space-2);
    padding-bottom: var(--space-2);
  }

  .main-nav-list {
    justify-content: flex-start;
  }

  .main-nav-item {
    margin-left: 0;
    margin-right: var(--space-2);
  }
}

@media (max-width: 640px) {
  .top-bar-inner {
    justify-content: center;
  }

  .footer-inner {
    flex-direction: column;
  }

  .footer-bottom-inner {
    text-align: center;
  }
}
